// Get the AI Agent's output data (current item for the Code node)
const aiAgentOutputItem = items[0];
// Assuming the AI output {idea_1:...} is directly in the json property
const ideasObject = aiAgentOutputItem.json;

// *** Get context data from the 'Edit Fields' node using the new expressions ***
// We assume the node is named 'Edit Fields'. If not, update the name within the $() calls.
// We also use .first() to ensure we get the item from the first run if the node ran multiple times.
// Using try-catch block for better error handling around accessing node data.
let contextDataJson;
try {
    // Attempt to get the JSON data from the 'Edit Fields' node's first item
    contextDataJson = $('Edit Fields').first().json;

    // Check if context data JSON exists after retrieval
    if (!contextDataJson) {
        throw new Error("JSON data is missing from the 'Edit Fields' node's first item.");
    }
} catch (error) {
    console.error(`Error accessing data from node 'Edit Fields': ${error.message}`);
    // Depending on requirements, you might want to throw the error again
    // or return an empty array if context is absolutely required.
    throw new Error(`Could not retrieve valid JSON data from node 'Edit Fields'. Please check the node name and ensure it ran successfully and produced JSON output. Original error: ${error.message}`);
}


const newItems = []; // Array to hold the new items

// Check if ideasObject exists and is an object
if (!ideasObject || typeof ideasObject !== 'object' || Object.keys(ideasObject).length === 0) {
    console.warn("Input 'ideasObject' is missing, not an object, or empty:", JSON.stringify(aiAgentOutputItem.json));
    // Return empty array if there are no ideas to process
    return [];
}

// Loop through each idea provided by the AI Agent
for (const ideaKey in ideasObject) {
    // Ensure we are iterating over own properties, not inherited ones
    if (ideasObject.hasOwnProperty(ideaKey)) {
        const ideaData = ideasObject[ideaKey]; // The specific idea's data (summary, angle, etc.)

        // Ensure ideaData is valid (e.g., an object) before processing
        if (ideaData && typeof ideaData === 'object') {

            // Combine the specific idea data and the context data using the new expressions
            const combinedData = {
                ...ideaData, // Spread the idea data (summary, angle, details, relevance)

                // Add context fields using the new expressions.
                // Using nullish coalescing (??) provides a default empty string if a field is missing.
                'Tone of voice': contextDataJson['Tone of voice'] ?? '', // Accessing with brackets for space
                'Topic': contextDataJson.Topic ?? '',                     // Added Topic
                'Platform': contextDataJson.Platform ?? '',               // Added Platform
                'Avatar': contextDataJson.Avatar ?? '',
                'problem you solve': contextDataJson['problem you solve'] ?? '', // Keep existing ones if needed
                'CTA': contextDataJson.CTA ?? '',
                'Make Content on': contextDataJson['Make Content on'] ?? '' // Keep existing ones if needed
            };

            // Create the new item structure expected by the workflow
            newItems.push({ json: combinedData });

        } else {
            // Log a warning if data for a specific idea key isn't valid
            console.warn(`Data for idea key "${ideaKey}" is not a valid object, skipping item creation. Data received:`, JSON.stringify(ideaData));
        }
    }
}

// Check if any items were actually created before returning
if (newItems.length === 0) {
    console.warn("No valid idea items were created from the input ideasObject. Check the AI output and the loop logic.");
}

// Return the array of newly structured items
return newItems;

const base64String = $json.B64;

const binaryData = Buffer.from(base64String, 'base64');

return {
